import{_ as e,o as a,c as o,a2 as d}from"./chunks/framework.DeNJmwJc.js";const p=JSON.parse('{"title":"Chapter 40 — Tabs","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/40-tabs.md","filePath":"chapters/40-tabs.md"}'),r={name:"chapters/40-tabs.md"};function i(s,t,c,n,h,l){return a(),o("div",null,[...t[0]||(t[0]=[d('<h1 id="chapter-40-—-tabs" tabindex="-1">Chapter 40 — Tabs <a class="header-anchor" href="#chapter-40-—-tabs" aria-label="Permalink to &quot;Chapter 40 — Tabs&quot;">​</a></h1><blockquote><p><em>&quot;Think of tabs as different workspaces, not different files.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐⭐⭐ Intermediate <strong>Estimated Reading Time:</strong> 10 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Vim tabs are <strong>collections of windows</strong>, not individual files.</p><p>They let you organize different working contexts.</p><hr><h1 id="tab-commands" tabindex="-1">Tab Commands <a class="header-anchor" href="#tab-commands" aria-label="Permalink to &quot;Tab Commands&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>:tabnew</code></td><td>Create new tab</td></tr><tr><td><code>:tabedit file</code></td><td>Open file in new tab</td></tr><tr><td><code>:tabclose</code></td><td>Close current tab</td></tr><tr><td><code>:tabnext</code> or <code>gt</code></td><td>Next tab</td></tr><tr><td><code>:tabprev</code> or <code>gT</code></td><td>Previous tab</td></tr><tr><td><code>:tabmove 0</code></td><td>Move tab to first position</td></tr><tr><td><code>:tabs</code></td><td>List all tabs</td></tr><tr><td><code>:tabonly</code></td><td>Close all other tabs</td></tr><tr><td><code>{i}gt</code></td><td>Go to tab number i</td></tr></tbody></table><hr><h1 id="key-mappings" tabindex="-1">Key Mappings <a class="header-anchor" href="#key-mappings" aria-label="Permalink to &quot;Key Mappings&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>gt</code></td><td>Next tab</td></tr><tr><td><code>gT</code></td><td>Previous tab</td></tr><tr><td><code>3gt</code></td><td>Go to tab 3</td></tr><tr><td><code>Ctrl+PageUp</code></td><td>Previous tab</td></tr><tr><td><code>Ctrl+PageDown</code></td><td>Next tab</td></tr></tbody></table><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h1><ul><li><code>gt</code>/<code>gT</code> navigate tabs.</li><li><code>:tabnew</code> creates a new tab.</li><li>Tabs contain windows; windows show buffers.</li><li>Use tabs for different projects or contexts.</li></ul><hr><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">​</a></h2><ol><li>Open a file in a new tab with <code>:tabedit</code>.</li><li>Navigate with <code>gt</code> and <code>gT</code>.</li><li>Create 3 tabs and switch between them.</li><li>Close a tab with <code>:tabclose</code>.</li></ol><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">​</a></h2><p><a href="./41-jump-list.html"><strong>Chapter 41 — Jump List</strong></a></p><p>Navigate through your cursor position history.</p>',24)])])}const m=e(r,[["render",i]]);export{p as __pageData,m as default};
